    /// <summary>
    /// Wire-nav step of the two-pass populate pattern. Invoked exactly
    /// once by <c>GeoDataInitializer</c> after every catalog's first-pass
    /// static ctor has run. Walks the country catalog and populates
    /// each currency's <c>AcceptedInCountryIso31661Alpha2Codes</c> set
    /// + <c>AcceptedInCountries</c> nav list via the friend-assembly
    /// <c>internal set</c> accessors.
    /// </summary>
    internal static void WireNav()
    {
        var grouped = new Dictionary<CurrencyCode, List<Country>>();
        foreach (var country in CountryLookup.All)
        {
            foreach (var cc in country.Currencies)
            {
                if (!grouped.TryGetValue(cc.Iso4217AlphaCode, out var list))
                {
                    list = new List<Country>();
                    grouped[cc.Iso4217AlphaCode] = list;
                }

                if (!list.Contains(country))
                    list.Add(country);
            }
        }

        foreach (var kvp in grouped)
        {
            if (!ByCode.TryGetValue(kvp.Key, out var currency))
                continue;

            currency.AcceptedInCountries = kvp.Value.ToArray();

            var codeSet = new HashSet<CountryCode>();
            foreach (var c in kvp.Value)
                codeSet.Add(c.Iso31661Alpha2Code);

            currency.AcceptedInCountryIso31661Alpha2Codes = codeSet.ToFrozenSet();
        }
    }
